const clamp=(n,r,e)=>Math.max(r,Math.min(n,e));function precisionRound(n,r=1){r=Math.pow(10,r);return Math.round(n*r)/r}function precision(n){return((""+n).split(".")[1]||"").length}function decimatedClamp(n,r,e,t){if(null==t||t<=0)return clamp(n,r,e);var i=precision(t),n=precisionRound(Math.round((n-r)/t)*t,i),e=precisionRound(Math.floor((e-r)/t)*t,i);return r+clamp(n,0,e)}function rescale(n,r,e,t={}){return decimatedClamp((n-r[0])/(r[1]-r[0])*(e[1]-e[0])+e[0],e[0],e[1],t.step)}export{clamp,precisionRound,rescale};